    static void addActionCenterUserList(Array _userArray,str _title, str _message,str _originClass)
    {
        // Set up the notification
        SystemNotificationDataContract notification = new SystemNotificationDataContract();
        notification.Users(_userArray); 
        notification.Title(_title);
        notification.RuleId(_originClass);
        notification.Message(_message);
        notification.ExpirationDateTime(DateTimeUtil::addHours(DateTimeUtil::utcNow(), 48)); // Expiration time is 48 hours

        SystemNotificationsManager::AddSystemNotification(notification);
    }

    static void addActionCenterSingleUser(str _userId,str _title, str _message,str _originClass)
    {
        // Set up the notification
        SystemNotificationDataContract notification = new SystemNotificationDataContract();
        notification.Users().value(1, _userId);
        notification.Title(_title);
        notification.RuleId(_originClass);
        notification.Message(_message);
        notification.ExpirationDateTime(DateTimeUtil::addHours(DateTimeUtil::utcNow(), 48)); // Expiration time is 48 hours

        SystemNotificationsManager::AddSystemNotification(notification);
    }
